queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?program_type_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:program_type_id ?cg . ?child a :Programs ; p:program_type_id ?cg . ?l p:radio_station_id ?pg . ?parent a :Radio_Stations ; p:station_id ?pg . } GROUP BY ?child }
  ?child p:program_type_name ?program_type_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Radio_Stations } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?station_name ?program_type_name WHERE {
  ?radio_stations_programs a :Radio_Stations_Programs .
  ?programs a :Programs .
  ?radio_stations_programs p:hasPrograms ?programs .
  ?radio_stations a :Radio_Stations .
  ?radio_stations_programs p:hasRadio_Stations ?radio_stations .
  ?radio_stations p:station_name ?station_name .
  ?programs p:program_type_name ?program_type_name .
} }
  collective: { SELECT ?program_type_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:program_type_id ?cg . ?child a :Programs ; p:program_type_id ?cg . ?l p:radio_station_id ?pg . ?parent a :Radio_Stations ; p:station_id ?pg . } GROUP BY ?child }
  ?child p:program_type_name ?program_type_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Radio_Stations } }
  FILTER(?nf = ?total)
} }
}
